import React from 'react';
import { useWebSocket } from './hooks/useWebSocket';
import DashboardOverview from './components/DashboardOverview';
import QueryAnalytics from './components/QueryAnalytics';
import ProductionScore from './components/ProductionScore';
import { AgentRegistry } from './components/AgentRegistry';
import { SystemTerminal } from './components/SystemTerminal';
import { motion, AnimatePresence } from 'framer-motion';

function App() {
    const { data, isConnected } = useWebSocket('ws://localhost:8000/ws');

    return (
        <div
            className="min-h-screen bg-black text-white p-6 md:p-10 font-sans selection:bg-white selection:text-black relative overflow-hidden scanline"
            style={{ backgroundColor: '#000000', color: '#FFFFFF' }}
        >

            {/* Background Branding Elements */}
            <div className="fixed -bottom-10 -right-10 pointer-events-none opacity-[0.03] select-none">
                <div className="text-[300px] font-black tracking-tighter leading-none">NX</div>
            </div>

            <div className="max-w-[1600px] mx-auto relative z-10">

                {/* Header Section */}
                <header className="flex flex-col md:flex-row justify-between items-start md:items-center mb-12 space-y-4 md:space-y-0">
                    <div className="flex flex-col">
                        <div className="flex items-center space-x-3">
                            <motion.div
                                initial={{ scale: 0 }}
                                animate={{ scale: 1 }}
                                className="w-8 h-8 bg-white rounded-full flex items-center justify-center p-2"
                            >
                                <div className="w-full h-full bg-black rounded-sm rotate-45" />
                            </motion.div>
                            <h1 className="text-3xl font-black tracking-tighter leading-none">APEX.NEXUS</h1>
                        </div>
                        <div className="flex items-center space-x-2 mt-2">
                            <span className="nothing-text-label tracking-widest text-[#FF3B30] opacity-80">MULTI-AGENT CONTROL PLANE</span>
                            <span className="text-[10px] text-white/10">/</span>
                            <span className="nothing-text-label opacity-40">VER.1.2.0_STABLE</span>
                        </div>
                    </div>

                    <div className="flex items-center space-x-8">
                        <div className="flex flex-col items-end">
                            <span className="nothing-text-label opacity-40 mb-1">TELEMETRY_LINK</span>
                            <div className="flex items-center space-x-3">
                                <span className={`text-[10px] font-black tracking-widest ${isConnected ? 'text-white' : 'text-[#FF3B30]'}`}>
                                    {isConnected ? 'LIVE_STREAMING' : 'DISCONNECTED'}
                                </span>
                                <div className={`w-1.5 h-1.5 rounded-full ${isConnected ? 'bg-white shadow-[0_0_8px_white] animate-pulse' : 'bg-[#FF3B30]'}`} />
                            </div>
                        </div>
                        <div className="h-8 w-[1px] bg-white/10 hidden md:block" />
                        <div className="flex flex-col items-end">
                            <span className="nothing-text-label opacity-40 mb-1">LOCAL_TIME</span>
                            <span className="text-[10px] font-mono tracking-widest">
                                {new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' })}
                            </span>
                        </div>
                    </div>
                </header>

                <main className="grid grid-cols-12 gap-6">

                    {/* Left Column: Metrics & Readiness (3/12) */}
                    <div className="col-span-12 xl:col-span-3 space-y-6">
                        <motion.div
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            className="nothing-card"
                        >
                            <h3 className="nothing-text-label mb-8">System_Pulse</h3>
                            <DashboardOverview />
                        </motion.div>

                        <motion.div
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            transition={{ delay: 0.2 }}
                            className="nothing-card min-h-[300px]"
                        >
                            <h3 className="nothing-text-label mb-8">Production_Integrity</h3>
                            <ProductionScore data={data} />
                        </motion.div>
                    </div>

                    {/* Middle Column: Routing Analytics (6/12) */}
                    <div className="col-span-12 xl:col-span-6">
                        <motion.div
                            initial={{ opacity: 0, scale: 0.98 }}
                            animate={{ opacity: 1, scale: 1 }}
                            className="nothing-card h-full min-h-[500px] flex flex-col"
                        >
                            <div className="flex-grow">
                                <QueryAnalytics data={data} />
                            </div>
                        </motion.div>
                    </div>

                    {/* Right Column: Registry & Terminal (3/12) */}
                    <div className="col-span-12 xl:col-span-3 space-y-6">
                        <motion.div
                            initial={{ opacity: 0, x: 20 }}
                            animate={{ opacity: 1, x: 0 }}
                            className="nothing-card"
                        >
                            <h3 className="nothing-text-label mb-6">Agent_Registry</h3>
                            <AgentRegistry />
                        </motion.div>

                        <motion.div
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.4 }}
                            className="nothing-card bg-black/60 min-h-[220px]"
                        >
                            <SystemTerminal logs={data?.alerts} />
                        </motion.div>
                    </div>
                </main>
            </div>

            {/* Global scanning line overlay - very subtle */}
            <div className="fixed inset-0 pointer-events-none pointer-events-none opacity-[0.02]">
                <div className="w-full h-[2px] bg-white animate-scan-y" />
            </div>
        </div>
    );
}

export default App;
